Let $T>0$, let $V\in L^\infty(\R^n\times[0,T];\C)$, and let $u\in C([0,T];L^2(\R^n))$ satisfy, for every $0\le s\le t\le T$,
\begin{equation}\label{eq:duhamel}
u(t)=e^{i(t-s)\Delta}u(s)+i\int_s^t e^{i(t-r)\Delta}\bigl(V(r)u(r)\bigr)\,dr\quad\text{in }L^2(\R^n).
\end{equation}
Put $x_{1,+}=\max\{x_1,0\}$. Assume that there is $c\in L^\infty([0,T];\C)$ such that
\begin{equation}\label{eq:tail-mod-scalar}
\lim_{R\to\infty}\int_0^T\norm{V(\cdot,t)-c(t)}_{L^\infty(\{x_1>R\})}\,dt=0,
\end{equation}
and that, for some $c_0,c_1>0$,
\begin{equation}\label{eq:endpoint-data}
e^{c_0x_{1,+}^2}u(0),\qquad e^{c_1x_{1,+}^2}u(T)\in L^2(\R^n).
\end{equation}
If $T^2c_0c_1>1/16$, then $u\equiv0$ on $\R^n\times[0,T]$.

Let $\phi=\phi(x_1,t)$ be real $C^4$ in $x_1$ and $C^2$ in $t$. For $f=e^\phi u$, define $S=-2i\phi_1\partial_{x_1}-i\phi_{11}+\phi_t$, $A=i\Delta+i\phi_1^2$. Then $S$ is symmetric, $A$ is skew-symmetric on $C_c^\infty(\R^n)$, and
\begin{equation}\label{eq:conjugated-operator}
e^\phi(\partial_t-i\Delta)e^{-\phi}f=\partial_tf-Sf-Af.
\end{equation}
Moreover,
\begin{align}\label{eq:commutator-form}
\langle(S_t+[S,A])f,f\rangle={}&4\int_{\R^n}\phi_{11}|\partial_{x_1}f|^2\,dx+4\int_{\R^n}\phi_{11}\phi_1^2|f|^2\,dx\notag\\
&-\int_{\R^n}\phi_{1111}|f|^2\,dx+\int_{\R^n}\phi_{tt}|f|^2\,dx+4\operatorname{Im}\int_{\R^n}\phi_{1t}\partial_{x_1}f\,\overline f\,dx.\notag
\end{align}
The transverse Laplacian contributes nothing to the commutator.

Use the Fourier transform on $\R^n$. Let $P_\pm$ be the orthogonal Fourier projections with symbols $\one_{\{\pm\xi_1>0\}}$. Let $m\in C_c^\infty(\R^n)$, $M_\varepsilon$ have symbol $m(\varepsilon\xi)$, and put $Q_{\varepsilon,\pm}=M_\varepsilon P_\pm$. Suppose $a=a(x_1)$ is real bounded, $a'\in C_c^\infty(\R)$. Then
 egin{align}

orm{[Q_{\varepsilon,\pm},a]\partial_{x_1}f}_2+
orm{\partial_{x_1}[Q_{\varepsilon,\pm},a]f}_2\le C_m
orm{\widehat{a'}}_{L^1(\R)}
orm f_2.\label{eq:fourier-commutator}
\end{align}
If $a\ge0$, then $\operatorname{Im}\langle Q_{\varepsilon,+}(a^2\partial_{x_1}f),Q_{\varepsilon,+}fangle\ge -C_a
orm f_2^2$ and $\operatorname{Im}\langle Q_{\varepsilon,-}(a^2\partial_{x_1}f),Q_{\varepsilon,-}fangle\le C_a
orm f_2^2$. For real bounded $b$,
 egin{equation}\label{eq:skew-transport}
|\operatorname{Re}\langle Q_{\varepsilon,\pm}(b\partial_{x_1}f),Q_{\varepsilon,\pm}fangle|\le C_m(
orm{b'}_\infty+
orm{\widehat{b'}}_1)
orm f_2^2.
\end{equation}

Let $u\in C([0,1];L^2(\R^n))$ satisfy $i\partial_tu+\Delta u=Vu+H$ in the Duhamel sense, where $V\in L^1([0,1];L^\infty)$, $H\in L^1([0,1];L^2)$. There exists $\varepsilon_n>0$ such that if $
orm V_{L^1_tL^\infty_x}\le\varepsilon_n$ and for one fixed $ eta>0$, $e^{ eta x_1}u(0),e^{ eta x_1}u(1),e^{ eta x_1}H\in L^2$ (resp. $L^1_tL^2_x$), then
 egin{equation}\label{eq:linear-exponential-bound}
\sup_{0\le t\le1}
orm{e^{ eta x_1}u(t)}_2\le C_n(
orm{e^{ eta x_1}u(0)}_2+
orm{e^{ eta x_1}u(1)}_2+
orm{e^{ eta x_1}H}_{L^1_tL^2_x}).
\end{equation}
The constant $C_n$ is independent of $ eta$.

Let $J=[c,d]$, let $S(t)$ be symmetric and $A(t)$ skew-symmetric on a common dense domain in $L^2$, and let $f$ be smooth domain-valued. Put $H=\norm f_2^2$, $D=\langle Sf,f\rangle$, $E=\partial_tf-Sf-Af$. Assume $\langle(S_t+[S,A])f,f\rangle\ge-\kappa H$ for $\kappa\ge0$. For $\varepsilon>0$, let $M_\varepsilon$ solve $M_\varepsilon''=-\norm E_2^2/(H+\varepsilon)$, $M_\varepsilon(c)=M_\varepsilon(d)=0$, and set $N_\varepsilon=\int_c^d|\operatorname{Re}\langle E,f\rangle|/(H+\varepsilon)\,dt$. Then
\begin{equation}\label{eq:abstract-logconv-output}
H(t)+\varepsilon\le(H(c)+\varepsilon)^{\vartheta(t)}(H(d)+\varepsilon)^{1-\vartheta(t)}\exp\{\kappa(t-c)(d-t)+M_\varepsilon(t)+2N_\varepsilon\}.
\end{equation}
If $E=iVf$ with $V\in L^\infty$, then $0\le M_\varepsilon(t)\le(d-c)^2\norm V_\infty^2/8$, $N_\varepsilon\le(d-c)\norm V_\infty$.

Under the notation of Lemma~\ref{lem:SA-logconv}, let $\gamma\in C^1([c,d])$ be positive and assume $\langle(\gamma S_t+\gamma[S,A]+\gamma'S)f,f\rangle\ge-\psi(t)H(t)$ with $\psi\ge0$. Let $T,M_\varepsilon$ be zero-boundary solutions $(\gamma T')'=-\psi$, $(\gamma M_\varepsilon')'=-\gamma\norm E_2^2/(H+\varepsilon)$. Put $\Theta(t)=\int_t^d\gamma^{-1}/\int_c^d\gamma^{-1}$. Then
\begin{equation}\label{eq:weighted-SA-output}
H(t)+\varepsilon\le(H(c)+\varepsilon)^{\Theta(t)}(H(d)+\varepsilon)^{1-\Theta(t)}\exp\{2T(t)+M_\varepsilon(t)+2N_\varepsilon\}.
\end{equation}

Let $u\in C([-1,1];L^2(\R^n))$ satisfy $\partial_tu=i(\Delta u+Vu)$ in the Duhamel sense, where $V\in L^\infty$ has integrably vanishing right tail. Suppose $e^{\mu x_{1,+}^2}u(-1),e^{\mu x_{1,+}^2}u(1)\in L^2$ for some $\mu>0$. There is a smooth convex $q:\R\to[0,\infty)$ with $q(r)=0\ (r\le0)$, $q(r)=r^2\ (r\ge1)$, such that for every $0<a<\mu$,
\begin{equation}\label{eq:verified-stationary-bound}
\sup_{-1\le t\le1}\norm{e^{aq(x_1)}u(t)}_2<\infty.
\end{equation}
Moreover, for every compact $I\Subset(-1,1)$, $\int_I\int_{\{x_1>1\}}e^{2ax_1^2}(|\partial_{x_1}u|^2+x_1^2|u|^2)\,dx\,dt<\infty$.

For positive smooth $a$, put $c=a^{-1/2}$ and $F(a)=\frac1a(a''-3(a')^2/(2a)+32a^3)$. Then $F(a)=\frac2c(16c^{-3}-c'')$. Fix $\mu>0$. Suppose $a_k=c_k^{-2}$ is positive even on $[-1,1]$, $a_k(\pm1)=\mu$, $a_k$ nonincreasing on $[0,1]$, $F(a_k)>0$. Let $b_k$ solve $b_k''=-2c_k(16c_k^{-3}-c_k''),\ b_k(\pm1)=0$. Then $b_k$ is even, strictly positive on $(-1,1)$, nonincreasing on $[0,1]$. If $1-a_kb_k>0$ and $a_{k+1}=a_k/(1-a_kb_k)$, $c_{k+1}=(c_k^2-b_k)^{1/2}$, then $a_{k+1}$ has all the same structural properties. Moreover,
\begin{equation}\label{eq:verified-weighted-identity}
\frac1\mu=c_{k+1}(0)^2+\int_0^1(1-t)(32a_k(t)+2(c_k'(t))^2)\,dt.
\end{equation}
Starting with $a_1\equiv\mu$, if the iteration is infinite and $\sup_ka_k(0)<\infty$, then $\mu\le1/8$.

There is a smooth convex $Q:\R\to[0,\infty)$ with $Q(y)=0\ (y\le0)$, $Q(y)=y^2-C_Q\ (y\ge1)$, $0\le Q'(y)/y\le2$, and $D_Q=4Q''(Q')^2-Q''''-16yQ'$ supported in $[0,1]$. Let $a,b$ be smooth real, $a>0$, $\xi\ge0$, put $y=\sqrt a(x_1+b\xi)$, $\phi=Q(y)$, $\gamma=a^{-1}$. For the operators $S,A$ of Lemma~\ref{lem:commutator},
\begin{align}\label{eq:moving-gaussian-completion}
\langle(\gamma S_t+\gamma[S,A]+\gamma'S)f,f\rangle={}&4\int Q''(y)|-i\partial_{x_1}f+\frac{y_t}{2\sqrt a}f|^2\,dx\notag\\
&+\int\Bigl[aD_Q+\frac{F(a)}{2a}yQ'+\frac{b''\xi}{\sqrt a}Q'\Bigr]|f|^2\,dx.
\end{align}
If $F(a)>0$, then $\langle(\gamma S_t+\gamma[S,A]+\gamma'S)f,f\rangle\ge-(|b''|^2\xi^2/F(a)+K_Qa)\norm f_2^2$. Assuming additionally that $a,b$ are even, $a$ nonincreasing on $[0,1]$, $c=a^{-1/2}$, $b''=-2c(16c^{-3}-c'')$, $b(\pm1)=0$, and $T$ solves $(a^{-1}T')'=-|b''|^2/F(a)$, then $0\le T(t)\le b(t)$.

Let $u\in C([-1,1];L^2(\R^n))$ be a Duhamel solution of $\partial_tu=i(\Delta u+Vu)$, $V\in L^\infty$. Let $a,b\in C^\infty([-1,1])$ be even, $a>0$ nonincreasing on $[0,1]$, $a(\pm1)=\mu$, $b(\pm1)=0$, $F(a)>0$. Suppose $\sup_{[-1,1]}
orm{e^{(a(t)-\eta)x_{1,+}^2}u(t)}_2<\infty$ for every $0<\eta<\min a$, and $E_\mu=
orm{e^{\mu x_{1,+}^2}u(-1)}_2+
orm{e^{\mu x_{1,+}^2}u(1)}_2<\infty$. Let $T$ be the zero-boundary solution $(a^{-1}T')'=-|b''|^2/F(a)$. Then for every $\xi\ge0$,
 egin{equation}\label{eq:verified-shifted-estimate}

orm{e^{a(t)(x_1+b(t)\xi)_+^2}u(t)}_2^2\le C_*e^{2T(t)\xi^2},\qquad -1\le t\le1,
\end{equation}
where $C_*$ depends only on $E_\mu$, $
orm V_\infty$, $Q$, and $\int_0^1a$.

Let $R>0$, $x_0\in\R$, $\varphi\in C^2([0,1];\R)$, put $z(x,t)=(x_1-x_0)/R+\varphi(t)$, $M_1=
orm{\varphi'}_\infty$, $M_2=
orm{\varphi''}_\infty$. If $g\in C_c^\infty(\R^n	imes(0,1))$, $\operatorname{supp}g\subset\{|z|\ge1\}$, and $\alpha>0$, $\alpha^2/R^4\ge(M_2+3M_1^2)/4$, then
 egin{equation}\label{eq:moving-quadratic-carleman}
 rac{\alpha^{3/2}}{R^2}
orm{e^{\alpha z^2}g}_{L^2}\le rac1{2\sqrt2}
orm{e^{\alpha z^2}(i\partial_t+\Delta)g}_{L^2}.
\end{equation}

There is a numerical constant $\Lambda<\infty$ with the following property. Let $u\in C([0,1];L^2(\R^n))$ be a Duhamel solution of $\partial_tu=i(\Delta u+Vu)$, $V\in L^\infty$. Assume $\partial_{x_1}u$ is locally $L^2$ on $\{x_1>1\}\times(0,1)$ and for some $\sigma>\Lambda$,
\begin{align}\label{eq:right-strip-hypothesis}
K_\sigma^2:={}&\sup_{0\le t\le1}\int_{\{x_1>1\}}e^{2\sigma x_1^2}|u(x,t)|^2\,dx\notag\\
&+\int_{1/32}^{31/32}\int_{\{x_1>1\}}e^{2\sigma x_1^2}(|u|^2+|\partial_{x_1}u|^2)\,dx\,dt<\infty.
\end{align}
Then $u=0$ a.e. on $\{x_1>2\}\times(3/8,5/8)$. The constant $\Lambda$ is independent of $n,V,u,K_\sigma$.
